from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity):
        self.cache = OrderedDict()
        self.capacity = capacity

    def access(self, key):
        if key in self.cache:
            self.cache.move_to_end(key)
            return True  # Cache hit
        else:
            if len(self.cache) >= self.capacity:
                # Evict least recently used (first item)
                self.cache.popitem(last=False)
            self.cache[key] = True
            return False  # Cache miss

    def display(self):
        print("Current cache state:", list(self.cache.keys()))

# Example usage
cache = LRUCache(4)
accesses = [1, 2, 3, 1, 4, 2, 5]
hits = 0

for addr in accesses:
    if cache.access(addr):
        hits += 1
        print(f"Access {addr}: HIT")
    else:
        print(f"Access {addr}: MISS")
    cache.display()

print(f"Total hits: {hits}")

#include <stdio.h>

#define CACHE_SIZE 64      // Number of cache lines
#define BLOCK_SIZE 16      // Bytes per block
#define CACHE_MASK 63      // 64 lines: 0-63

typedef struct {
    int valid;
    int tag;
    int data;
} CacheLine;

CacheLine cache[CACHE_SIZE];

int accessMemory(int address) {
    int blockNumber = address / BLOCK_SIZE;
    int lineNumber = blockNumber & CACHE_MASK;  // blockNumber % 64
    int offset = address % BLOCK_SIZE;
    int tag = blockNumber / CACHE_SIZE;

    // Check for hit
    if (cache[lineNumber].valid && cache[lineNumber].tag == tag) {
        printf("HIT at line %d, offset %d\n", lineNumber, offset);
        return 1;  // Hit
    } else {
        // Miss - load block
        printf("MISS - loading block %d to line %d\n", blockNumber, lineNumber);
        cache[lineNumber].valid = 1;
        cache[lineNumber].tag = tag;
        return 0;  // Miss
    }
}

int main() {
    // Initialize cache
    for (int i = 0; i < CACHE_SIZE; i++) {
        cache[i].valid = 0;
    }

    int addresses[] = {100, 260, 564, 1024, 100, 260};
    int n = sizeof(addresses) / sizeof(addresses[0]);
    int hits = 0, misses = 0;

    for (int i = 0; i < n; i++) {
        if (accessMemory(addresses[i]))
            hits++;
        else
            misses++;
    }

    printf("\nTotal: Hits=%d, Misses=%d\n", hits, misses);
    printf("Hit Ratio: %.2f\n", (float)hits / n);

    return 0;
}

public class WriteBackCache {
    private CacheLine[] cache;
    private int cacheSize;

    public WriteBackCache(int size) {
        this.cacheSize = size;
        this.cache = new CacheLine[size];
        for (int i = 0; i < size; i++) {
            cache[i] = new CacheLine();
        }
    }

    private class CacheLine {
        boolean valid = false;
        boolean dirty = false;
        int tag = 0;
        int data = 0;
    }

    public void write(int address, int data) {
        int line = address % cacheSize;
        int tag = address / cacheSize;

        if (cache[line].valid && cache[line].tag == tag) {
            // Write hit - update cache only
            cache[line].data = data;
            cache[line].dirty = true;
            System.out.println("WRITE HIT: Updated cache line " + line + 
                             " (marked dirty)");
        } else {
            // Write miss
            if (cache[line].dirty) {
                // Write back dirty block to memory
                System.out.println("WRITE BACK: Saving dirty block from line " + line);
            }
            // Load new block
            cache[line].valid = true;
            cache[line].tag = tag;
            cache[line].data = data;
            cache[line].dirty = true;
            System.out.println("WRITE MISS: Loaded block to line " + line);
        }
    }

    public static void main(String[] args) {
        WriteBackCache cache = new WriteBackCache(4);

        System.out.println("--- Writing 10, 14, 10, 18 to cache ---");
        cache.write(10, 100);
        cache.write(14, 200);
        cache.write(10, 150);  // Should hit - same line as 10
        cache.write(18, 300);  // Should cause write back
    }
}
